VenueName.courtDataLoadCallBack = function() {
	Services.setValue(VenueCode.dataBinding, WPU.getCaseOwningCourt());
	Services.setValue(SelectVenue_VenueCode.dataBinding, WPU.getCaseOwningCourt()); }


var NEW_HEARING_VENUE_TMP_PATH_Q14 = "/ds/var/page/Tmp/Venue";
var NEW_HEARING_TMP_PATH = "/ds/var/page/Tmp/Hearing";

function setOwningCrtDetails() {			   	
   	var hcrtcode  =  WPU.getCaseOwningCourt();			   
   	var addxpath = REF_DATA_XPATH + "/Courts/Court[./Code='"+hcrtcode+"']/ContactDetails/Address"; 
   	var xpathName = REF_DATA_XPATH + "/Courts/Court[./Code='"+hcrtcode+"']/Name";   	 			   	 
   	Services.setValue(VenueCode.dataBinding, hcrtcode);
   	Services.setValue(SelectVenue_VenueCode.dataBinding, hcrtcode);   	 
   	Services.setValue(VenueName.dataBinding, Services.getValue(xpathName));	   	 			   	 		   	 
   	var addAr = Services.getNodes(addxpath);
   	if (null != addAr && addAr.length == 1) {				   	 	
   	 	var ln1 = Services.getValue(addxpath+"/Line[1]");
   	 	var ln2 = Services.getValue(addxpath+"/Line[2]");
   	 	var ln3 = Services.getValue(addxpath+"/Line[3]");
   	 	var ln4 = Services.getValue(addxpath+"/Line[4]");
   	 	var ln5 = Services.getValue(addxpath+"/Line[5]");
   	 	var pcode = Services.getValue(addxpath+"/PostCode");
   	 	Services.setValue(AdLine1.dataBinding, ln1);
	 	Services.setValue(AdLine2.dataBinding, ln2);
	 	Services.setValue(AdLine3.dataBinding, ln3);
	 	Services.setValue(AdLine4.dataBinding, ln4);
	 	Services.setValue(AdLine5.dataBinding, ln5);
	 	Services.setValue(Postcode.dataBinding, pcode); } }

function VenueCode() {}
VenueCode.tabIndex = __tabIdx++;
VenueCode.dataBinding = "/ds/EnterVariableData/HearingVenueCode";
VenueCode.isReadOnly = function(){ return true; }
VenueCode.maxLength = 3;
VenueCode.helpText = "Unique three digit court location code - list available.";
VenueCode.mandatoryOn = [VenueCode.dataBinding];
VenueCode.isMandatory = function(){	return VenueName.isMandatory(); }	
VenueCode.isTemporary = function(){  return true; }
VenueCode.logicOn = [VenueCode.dataBinding];
VenueCode.logic = function(xpath) {    
	var code = Services.getValue(VenueCode.dataBinding);     
    var xpathName = REF_DATA_XPATH + "/Courts/Court[./Code = " + VenueCode.dataBinding + "]/Name";
	var venueName = Services.getValue(xpathName);
    Services.setValue(VenueCode.dataBinding, code);
    Services.setValue(VenueName.dataBinding, venueName);
	Services.setValue(SelectVenue_VenueCode.dataBinding, code);
	Services.setValue(SelectVenue_VenueName.dataBinding, code);
	var address = REF_DATA_XPATH + "/Courts/Court[./Code = " + VenueCode.dataBinding + "]/ContactDetails/Address";		
	if (Services.countNodes(address) == 1) {	    
		var xid    = Services.getValue(address + "/Id");
	    var line1  = Services.getValue(address + "/Line[1]");
	    var line2  = Services.getValue(address + "/Line[2]");
	    var line3  = Services.getValue(address + "/Line[3]");
	    var line4  = Services.getValue(address + "/Line[4]");
	    var line5  = Services.getValue(address + "/Line[5]");
	    var pcode  = Services.getValue(address + "/PostCode");	    
		Services.setValue(REF_DATA_XPATH + "/Address/AddressId", xid);	
	    Services.setValue(AdLine1.dataBinding,line1);		   
	    Services.setValue(AdLine2.dataBinding,line2);
	    Services.setValue(AdLine3.dataBinding,line3);
	    Services.setValue(AdLine4.dataBinding,line4);
	    Services.setValue(AdLine5.dataBinding,line5);
	    Services.setValue(Postcode.dataBinding,pcode); }
	else {   
		Services.setValue(NEW_HEARING_TMP_PATH + "/Address/AddressId", '');	
		Services.setValue(AdLine1.dataBinding,'');		   
		Services.setValue(AdLine2.dataBinding,'');
		Services.setValue(AdLine3.dataBinding,'');
		Services.setValue(AdLine4.dataBinding,'');
		Services.setValue(AdLine5.dataBinding,'');
		Services.setValue(Postcode.dataBinding,'');	} }

VenueName.srcData = REF_DATA_XPATH + "/Courts";
VenueName.rowXPath = "Court";
VenueName.keyXPath = "Code";
VenueName.displayXPath = "Name";

