	Services.dispatchEvent("SelectVenue_Popup", PopupGUIAdaptor.EVENT_RAISE);
	var venueCode = Services.getValue(VenueCode.dataBinding);
	Services.setValue(SelectVenue_VenueCode.dataBinding, venueCode); }
/** PostBuildX 15a **/
VenueLOVBtn.additionalBindings = {
	eventBinding: {
		keys: [ { key: Key.F6, element: "VenueCode" }, { key: Key.F6, element: "VenueName" } ]
	}
};
			
