CourtsLOVGrid.logicOn = [CourtsLOVGrid.dataBinding];
CourtsLOVGrid.logic = function(xpath) {
	var courtCode = Services.getValue(CourtsLOVGrid.dataBinding);
	if (null != courtCode && "" != courtCode) {	
		var xpathName = REF_DATA_XPATH + "/Courts/Court[Code = " + courtCode + "]/Name";		
		var courtName = Services.getValue(xpathName); }
	Services.setValue(SelectVenue_VenueCode.dataBinding, courtCode);
	Services.setValue(SelectVenue_VenueName.dataBinding, courtCode); }

