		code = Services.getValue(REF_DATA_XPATH + "/Courts/Court[Name = " + SelectVenue_VenueName.dataBinding + "]/Code"); }
	if( code != null && code != "") { 	
		Services.setValue(SelectVenue_VenueCode.dataBinding, code); }
	else { 
		Services.setValue(SelectVenue_VenueName.dataBinding, "");
