function SelectVenue_OKBtn() {}
SelectVenue_OKBtn.tabIndex = __tabIdx++;
SelectVenue_OKBtn.enableOn = [NEW_HEARING_VENUE_TMP_PATH_Q14 + "/Address/Line[1]"];
SelectVenue_OKBtn.isEnabled = function() {	
	var c = Services.getValue(NEW_HEARING_VENUE_TMP_PATH_Q14 + "/Address/Line[1]");
	if(c != null && c!= "") {
		return true; }
	else {
		return false; } }
SelectVenue_OKBtn.actionBinding = function() {	
	var venueCode = Services.getValue(SelectVenue_VenueCode.dataBinding);
	var venueName = Services.getValue(SelectVenue_VenueName.dataBinding);
	var addressId = Services.getValue(selectVenue_Address_Grid.dataBinding);
	var add1 = Services.getValue(SelectVenue_ContactDetails_Address_Line1.dataBinding);
	var add2 = Services.getValue(SelectVenue_ContactDetails_Address_Line2.dataBinding);	
	var add3 = Services.getValue(SelectVenue_ContactDetails_Address_Line3.dataBinding);	
	var add4 = Services.getValue(SelectVenue_ContactDetails_Address_Line4.dataBinding);
	var add5 = Services.getValue(SelectVenue_ContactDetails_Address_Line5.dataBinding);
	var postcode = Services.getValue(SelectVenue_ContactDetails_Address_Postcode.dataBinding);		
	var dxNo = Services.getValue(SelectVenue_ContactDetails_Address_DXNumber.dataBinding);
	var telNo = Services.getValue(SelectVenue_ContactDetails_Address_TelephoneNumber.dataBinding);
	var faxNo = Services.getValue(SelectVenue_ContactDetails_Address_FaxNumber.dataBinding);
	var screenValid = true;
	if((venueCode == null || venueCode == "") || (venueName == null || venueName == "") || (add1 == null || add2 == "")){
		screenValid = false; }
	if(screenValid){
	 	var xpathName = REF_DATA_XPATH + "/Courts/Court[./Code = " + SelectVenue_VenueName.dataBinding + "]/Name";	 
	 	var checkVenueName = Services.getValue(xpathName);
	 	if( null != checkVenueName && checkVenueName.length > 0) {
    		venueName = checkVenueName; }
		Services.setValue(VenueCode.dataBinding, venueCode);		
		Services.setValue(VenueName.dataBinding, venueName);
		Services.setValue(NEW_HEARING_TMP_PATH + "/Address/AddressId", addressId);
		Services.setValue(AdLine1.dataBinding, add1);
		Services.setValue(AdLine2.dataBinding, add2);			
		Services.setValue(AdLine3.dataBinding, add3);
		Services.setValue(AdLine4.dataBinding, add4);
		Services.setValue(AdLine5.dataBinding, add5);
		Services.setValue(Postcode.dataBinding, postcode);			
		FormController.getInstance().hideFormExtensionPopup("SelectVenue");	}
	else{
		alert("Please ensure you have selected valid venue details."); } }

function SelectVenue_CancelBtn() {}
SelectVenue_CancelBtn.tabIndex = __tabIdx++;

selectVenue_Address_Grid.srcData = REF_DATA_XPATH + "/Courts/Court[./Code = " + CourtsLOVGrid.dataBinding + "]/ContactDetails"; //List of Courts/venues addresses
selectVenue_Address_Grid.rowXPath = "Address";		// Individual Court/venue
selectVenue_Address_Grid.keyXPath = "AddressId";  	// Unique identifier for a Court/venue
selectVenue_Address_Grid.columns = [   				// column bindings
	{xpath: "Line[1]", sort: function(a,b){if(a < b){return 1;};if(a > b){return -1;};return 0;}},
	{xpath: "Line[2]", sort: function(a,b){if(a < b){return 1;};if(a > b){return -1;};return 0;}} ];

selectVenue_Address_Grid.retrieveOn = [CourtsLOVGrid.dataBinding];
selectVenue_Address_Grid.srcDataOn = [CourtsLOVGrid.dataBinding];
selectVenue_Address_Grid.logicOn = [selectVenue_Address_Grid.dataBinding, CourtsLOVGrid.dataBinding];
selectVenue_Address_Grid.logic = function(xpath) {
	var courtCode = Services.getValue(CourtsLOVGrid.dataBinding);
	var addressId = Services.getValue(selectVenue_Address_Grid.dataBinding);
	if (courtCode != null && "" != courtCode && addressId != null && "" != addressId){
		var b11 = REF_DATA_XPATH + "/Courts/Court[./Code = ";
		var b13 = "]/ContactDetails/";
		var b12 = b13+"Address[./AddressId = ";
		var xpathAdd1 = b11+courtCode+b12+addressId+"]/Line[1]";	
		var xpathAdd2 = b11+courtCode+b12+addressId+"]/Line[2]";	
		var xpathAdd3 = b11+courtCode+b12+addressId+"]/Line[3]";	
		var xpathAdd4 = b11+courtCode+b12+addressId+"]/Line[4]";	
		var xpathAdd5 = b11+courtCode+b12+addressId+"]/Line[5]";	
		var xpathPostcode = b11+courtCode+b12+addressId+"]/PostCode";	
		var xpathDXNo = b11+courtCode+b13+"DX";	
		var xpathTelNo = b11+courtCode+b13+"TelephoneNumber";	
		var xpathFaxNo = b11+courtCode+b13+"FaxNumber";	
		var add1 = Services.getValue(xpathAdd1);
		var add2 = Services.getValue(xpathAdd2);
		var add3 = Services.getValue(xpathAdd3); if(add3 == null) add3 = "";	
		var add4 = Services.getValue(xpathAdd4); if(add4 == null) add4 = "";
		var add5 = Services.getValue(xpathAdd5); if(add5 == null) add5 = "";
		var postcode = Services.getValue(xpathPostcode);		
		var dxNo = Services.getValue(xpathDXNo);   if(dxNo == null)  dxNo = "";
		var telNo = Services.getValue(xpathTelNo); if(telNo == null) telNo = "";
		var faxNo = Services.getValue(xpathFaxNo); if(faxNo == null) faxNo= "";
		Services.setValue(SelectVenue_ContactDetails_Address_Line1.dataBinding, add1);
		Services.setValue(SelectVenue_ContactDetails_Address_Line2.dataBinding, add2);
		Services.setValue(SelectVenue_ContactDetails_Address_Line3.dataBinding, add3);
		Services.setValue(SelectVenue_ContactDetails_Address_Line4.dataBinding, add4);
		Services.setValue(SelectVenue_ContactDetails_Address_Line5.dataBinding, add5);
		Services.setValue(SelectVenue_ContactDetails_Address_Postcode.dataBinding, postcode);		
		Services.setValue(SelectVenue_ContactDetails_Address_DXNumber.dataBinding, dxNo);
		Services.setValue(SelectVenue_ContactDetails_Address_TelephoneNumber.dataBinding, telNo);
		Services.setValue(SelectVenue_ContactDetails_Address_FaxNumber.dataBinding, faxNo);	}
	else {
		Services.setValue(SelectVenue_ContactDetails_Address_Line1.dataBinding, "");
		Services.setValue(SelectVenue_ContactDetails_Address_Line2.dataBinding, "");
		Services.setValue(SelectVenue_ContactDetails_Address_Line3.dataBinding, "");
		Services.setValue(SelectVenue_ContactDetails_Address_Line4.dataBinding, "");
		Services.setValue(SelectVenue_ContactDetails_Address_Line5.dataBinding, "");
		Services.setValue(SelectVenue_ContactDetails_Address_Postcode.dataBinding, "");		
		Services.setValue(SelectVenue_ContactDetails_Address_DXNumber.dataBinding, "");
		Services.setValue(SelectVenue_ContactDetails_Address_TelephoneNumber.dataBinding, "");
		Services.setValue(SelectVenue_ContactDetails_Address_FaxNumber.dataBinding, ""); } }

Context.miscCode:
		VenueLOVBtn.enableOn = [HearingListed.dataBinding];
	  	VenueLOVBtn.isEnabled = function() {	
	  		var isListed = Services.getValue(HearingListed.dataBinding);
	  		return ('Y' == isListed); }	
	  	VenueCode.enableOn =  [HearingListed.dataBinding];
  		VenueCode.isEnabled = function() {	
	  		var isListed = Services.getValue(HearingListed.dataBinding);
	  		return ('Y' == isListed); }
  		VenueCode.logicOn = [HearingListed.dataBinding];
  		VenueCode.logic = function(xpath) {	
  			var isListed = Services.getValue(HearingListed.dataBinding);
	  		if('Y' != Services.getValue(HearingListed.dataBinding)) {	
  				Services.setValue(VenueCode.dataBinding, "");
  				Services.setValue(VenueName.dataBinding, ""); }
